// Stub: simulates ERP budget check response
// Replace this node with a real HTTP Request to your ERP API in production

const { cost_center, amount, currency, pr_id } = $input.first().json;

// Synthetic budget data per cost center
const budgets = {
  'CC-1001': { owner: 'Maria Schmidt', owner_email: 'maria.schmidt@company.com', available: 45000, currency: 'EUR' },
  'CC-1002': { owner: 'Thomas Bauer', owner_email: 'thomas.bauer@company.com', available: 120000, currency: 'EUR' },
  'CC-1003': { owner: 'Julia Wagner', owner_email: 'julia.wagner@company.com', available: 8500, currency: 'EUR' },
  'CC-1004': { owner: 'Stefan Hoffmann', owner_email: 'stefan.hoffmann@company.com', available: 250000, currency: 'EUR' }
};

const budget = budgets[cost_center] ?? { owner: 'Unknown', owner_email: 'procurement@company.com', available: 0, currency: 'EUR' };
const sufficient = budget.available >= parseFloat(amount);

return [{
  json: {
    pr_id,
    action: 'budget_check',
    cost_center,
    cost_center_head_name: budget.owner,
    cost_center_head_email: budget.owner_email,
    available_budget: budget.available,
    requested_amount: parseFloat(amount),
    currency: budget.currency,
    budget_sufficient: sufficient,
    checked_at: new Date().toISOString()
  }
}];

